import numpy as np

def initialize_params(n, method='random'):
    if method == 'random':
        return np.random.uniform(-np.pi, np.pi, n)
    elif method == 'zeros':
        return np.zeros(n)
    elif method == 'uniform_small':
        return np.random.uniform(-0.1, 0.1, n)
    else:
        return np.zeros(n)

for method in ['random', 'zeros', 'uniform_small']:
    p = initialize_params(5, method)
    print(f"{method}: {p}")
